import functools

def log_calls(func):
    @functools.wraps(func)          # preserve name, docstring, annotations
    def wrapper(*args, **kwargs):
        print(f"calling {func.__name__}({args}, {kwargs})")
        result = func(*args, **kwargs)
        print(f"{func.__name__} returned {result!r}")
        return result
    return wrapper

@log_calls                          # add = log_calls(add)
def add(a, b):
    """Return the sum of a and b."""
    return a + b

add(2, 3)
print(add.__name__)   # 'add'  (not 'wrapper', thanks to wraps)
print(add.__doc__)    # 'Return the sum of a and b.'

import functools, time

def retry(times=3, delay=0.0):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            for attempt in range(1, times + 1):
                try:
                    return func(*args, **kwargs)
                except Exception as exc:
                    print(f"attempt {attempt} failed: {exc}")
                    if attempt == times:
                        raise
                    time.sleep(delay)
        return wrapper
    return decorator

@retry(times=3, delay=0.1)
def flaky(n):
    if n < 3:
        raise ValueError("not ready")
    return "ok"

# retry(times=3, delay=0.1) returns 'decorator', which wraps flaky

import functools

@functools.cache                 # unbounded memoization (Python 3.9+)
def fib(n):
    return n if n < 2 else fib(n - 1) + fib(n - 2)

print(fib(50))                   # fast: each n computed once

@functools.lru_cache(maxsize=128)  # bounded variant + stats
def slow_square(n):
    return n * n

slow_square(4); slow_square(4)
print(slow_square.cache_info())   # CacheInfo(hits=1, misses=1, ...)

