import functools, time

def timed(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        start = time.perf_counter()
        result = func(*args, **kwargs)
        elapsed = (time.perf_counter() - start) * 1000
        print(f"{func.__name__} took {elapsed:.2f} ms")
        return result
    return wrapper

@timed
def work(n):
    """Sum 0..n-1."""
    return sum(range(n))

work(1_000_000)
print(work.__name__, "-", work.__doc__)  # work - Sum 0..n-1.

def timed_no_wraps(func):
    def wrapper(*args, **kwargs):
        return func(*args, **kwargs)
    return wrapper

@timed_no_wraps
def work(n):
    """Sum 0..n-1."""
    return sum(range(n))

print(work.__name__)  # 'wrapper'  <- identity lost
print(work.__doc__)   # None

import functools

def count_calls(label):
    def decorator(func):
        calls = 0
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            nonlocal calls
            calls += 1
            print(f"[{label}] call #{calls}")
            return func(*args, **kwargs)
        return wrapper
    return decorator

@count_calls(label="greet")
def greet(name):
    return f"hi {name}"

greet("Ada"); greet("Bob")  # [greet] call #1, then #2

@count_calls(label="task")   # outermost: runs first on each call
@timed                        # innermost: nearest the def
def task(n):
    return sum(range(n))

task(500_000)
# prints: [task] call #1   then   task took ... ms

