class Countdown:
    """Iterate from n down to 1."""
    def __init__(self, n):
        self.n = n

    def __iter__(self):
        return self            # an iterator returns itself

    def __next__(self):
        if self.n <= 0:
            raise StopIteration
        self.n -= 1
        return self.n + 1

for value in Countdown(3):
    print(value)               # 3, 2, 1

# The same thing as a generator — far less code:
def countdown(n):
    while n > 0:
        yield n
        n -= 1

