class Squares:
    def __init__(self, n):
        self.n = n
        self.i = 0
    def __iter__(self):
        return self
    def __next__(self):
        if self.i >= self.n:
            raise StopIteration
        self.i += 1
        return self.i * self.i

print(list(Squares(4)))   # [1, 4, 9, 16]
print([s for s in Squares(3)])  # [1, 4, 9]
